module bnn_demo_top (
    input        clk,       // 50MHz board clock, PIN_E1
    input        rst_n,     // board reset button, PIN_N13
    input        key1_n,    // PIN_M15, active-low, "next image" button
    output [3:0] led        // PIN_E10/F9/C9/D9
);

// 7 real MNIST test images, bit-identical to tb_bnn_core.v (bit[y*28+x] =
// pixel(y,x)). localparam, not reg+initial -- initial-block arrays aren't
// guaranteed to load as real ROM content on real silicon.
localparam [783:0] IMG0 = 784';
localparam [783:0] IMG1 = 784';
localparam [783:0] IMG2 = 784';
localparam [783:0] IMG3 = 784';
localparam [783:0] IMG4 = 784';
localparam [783:0] IMG5 = 784';
localparam [783:0] IMG6 = 784';

// combinational select driven by the runtime img_idx register (keeps the
// "don't let Quartus constant-fold this away" property from above)
reg [783:0] cur_image;
always @* begin
    case (img_idx)
        3'd0: cur_image = IMG0;
        3'd1: cur_image = IMG1;
        3'd2: cur_image = IMG2;
        3'd3: cur_image = IMG3;
        3'd4: cur_image = IMG4;
        3'd5: cur_image = IMG5;
        default: cur_image = IMG6;
    endcase
end

// KEY1 debounce + falling-edge pulse: 2-flop sync + saturating counter
// (~1.3ms at 50MHz before a new level is accepted as stable)
reg [15:0] db_cnt;
reg key1_sync0, key1_sync1, key1_stable, key1_stable_d;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        key1_sync0    <= 1'b1;
        key1_sync1    <= 1'b1;
        key1_stable   <= 1'b1;
        key1_stable_d <= 1'b1;
        db_cnt        <= 16'd0;
    end
    else begin
        key1_sync0 <= key1_n;
        key1_sync1 <= key1_sync0;
        if (key1_sync1 != key1_stable) begin
            db_cnt <= db_cnt + 16'd1;
            if (db_cnt == 16'hFFFF)
                key1_stable <= key1_sync1;
        end
        else begin
            db_cnt <= 16'd0;
        end
        key1_stable_d <= key1_stable;
    end
end
wire key1_pressed = key1_stable_d && !key1_stable;   // falling edge only

// ---- image index + bnn_core driver FSM ----
localparam [1:0] F_BOOT  = 2'd0,
                  F_IDLE  = 2'd1,
                  F_START = 2'd2,
                  F_WAIT  = 2'd3;

reg [1:0] fsm;
reg [3:0] boot_cnt;
reg [2:0] img_idx;
reg       start;
reg [3:0] result;

wire        done;
wire [3:0]  digit_out;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        fsm      <= F_BOOT;
        boot_cnt <= 4'd0;
        img_idx  <= 3'd0;
        start    <= 1'b0;
        result   <= 4'd0;
    end
    else begin
        start <= 1'b0;

        case (fsm)
            // short delay after reset so this FSM doesn't race bnn_core's own reset
            F_BOOT: begin
                if (boot_cnt == 4'd8) fsm <= F_START;
                else boot_cnt <= boot_cnt + 4'd1;
            end

            F_IDLE: begin
                if (key1_pressed) begin
                    img_idx <= (img_idx == 3'd6) ? 3'd0 : img_idx + 3'd1;
                    fsm     <= F_START;
                end
            end

            F_START: begin
                start <= 1'b1;
                fsm   <= F_WAIT;
            end

            F_WAIT: begin
                if (done) begin
                    result <= digit_out;
                    fsm    <= F_IDLE;
                end
            end

            default: fsm <= F_IDLE;
        endcase
    end
end

bnn_core u_bnn (
    .clk       (clk),
    .rst_n     (rst_n),
    .start     (start),
    .image_in  (cur_image),
    .done      (done),
    .digit_out (digit_out)
);

assign led = result;

endmodule
